namespace sv_b260a428fae645eeae9cbc422039c732.Services;

public class WarehouseInfo
{
    public string WarehouseId { get; set; } = "WH-001";
    public string WarehouseName { get; set; } = "Warehouse A";

    public static readonly (string Id, string Name)[] AvailableWarehouses =
    [
        ("WH-001", "Warehouse A"),
        ("WH-002", "Warehouse B"),
        ("WH-003", "Warehouse C"),
    ];
}

namespace sv_b260a428fae645eeae9cbc422039c732.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts per warehouse.
/// Fires OnChange so any subscribed component can re-render.
/// Scoped lifetime = one instance per circuit (per user), so each
/// warehouse manager gets independent state.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private CancellationTokenSource? _cts;
    private int _subscriberCount;
    private readonly object _lock = new();

    public int CurrentAlertCount { get; private set; }
    public event Action? OnChange;

    /// <summary>
    /// Simulates a database query returning low-stock item count.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Starts polling every 10 seconds for the given warehouse.
    /// Multiple callers share a single polling loop per circuit.
    /// </summary>
    public void StartPolling(string warehouseId)
    {
        lock (_lock)
        {
            _subscriberCount++;
            if (_subscriberCount > 1) return; // already polling
        }

        _cts = new CancellationTokenSource();
        _ = PollLoopAsync(warehouseId, _cts.Token);
    }

    /// <summary>
    /// Decrements subscriber count; stops polling when no subscribers remain.
    /// </summary>
    public void StopPolling()
    {
        lock (_lock)
        {
            _subscriberCount = Math.Max(0, _subscriberCount - 1);
            if (_subscriberCount > 0) return;
        }

        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    /// <summary>
    /// Restarts polling against a new warehouse (e.g. after warehouse switch).
    /// </summary>
    public void RestartPolling(string warehouseId)
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        _ = PollLoopAsync(warehouseId, _cts.Token);
    }

    private async Task PollLoopAsync(string warehouseId, CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                CurrentAlertCount = await GetLowStockCountAsync(warehouseId);
                OnChange?.Invoke();
                await Task.Delay(TimeSpan.FromSeconds(10), ct);
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

