using Microsoft.AspNetCore.Components;
using sv_b260a428fae645eeae9cbc422039c732.Components;
using sv_b260a428fae645eeae9cbc422039c732.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

// Warehouse selection cascaded app-wide via DI so it crosses render-mode
// boundaries (static layout → interactive children). Scoped per circuit.
builder.Services.AddCascadingValue(sp =>
{
    var info = new WarehouseInfo();
    return new CascadingValueSource<WarehouseInfo>(info, isFixed: false);
});

// Scoped so each circuit (user) gets independent alert state.
builder.Services.AddScoped<InventoryAlertService>();

arguments.file_text:
@rendermode InteractiveServer
@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@inject InventoryAlertService AlertService

<select class="form-select form-select-sm"
        value="@_selectedId"
        @onchange="OnWarehouseChanged"
        aria-label="Select warehouse">
    @foreach (var (id, name) in WarehouseInfo.AvailableWarehouses)
    {
        <option value="@id">@name</option>
    }
</select>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private string _selectedId = "WH-001";

    protected override void OnParametersSet()
    {
        if (Warehouse is not null)
            _selectedId = Warehouse.WarehouseId;
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString() ?? "WH-001";
        var match = WarehouseInfo.AvailableWarehouses
            .FirstOrDefault(w => w.Id == newId);

        var updated = new WarehouseInfo
        {
            WarehouseId = match.Id ?? newId,
            WarehouseName = match.Name ?? newId
        };

        // Push to all [CascadingParameter] subscribers across render modes
        await WarehouseSource.NotifyChangedAsync(updated);

        // Restart polling so alert counts reflect the new warehouse
        AlertService.RestartPolling(updated.WarehouseId);
    }
}

@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

<span class="badge bg-danger rounded-pill ms-2"
      style="@(AlertService.CurrentAlertCount == 0 ? "display:none" : "")">
    @AlertService.CurrentAlertCount
</span>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Wrap in InvokeAsync because OnChange fires from a background polling thread
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
    }
}

