@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Dashboard — @(Warehouse?.WarehouseName ?? "No warehouse")</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card text-bg-@(AlertService.CurrentAlertCount > 0 ? "warning" : "success")">
            <div class="card-body">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4">@AlertService.CurrentAlertCount</p>
                <p class="card-text text-muted">
                    Items below minimum level. Refreshes every 10 seconds.
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private Action? _handler;
    private string _lastWarehouseId = string.Empty;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;

        var whId = Warehouse?.WarehouseId ?? "WH-001";
        _lastWarehouseId = whId;
        AlertService.StartPolling(whId);
    }

    protected override void OnParametersSet()
    {
        // React when the cascaded warehouse changes (user picked a new one)
        var whId = Warehouse?.WarehouseId ?? "WH-001";
        if (whId != _lastWarehouseId)
        {
            _lastWarehouseId = whId;
            AlertService.RestartPolling(whId);
        }
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
        AlertService.StopPolling();
    }
}

